SELECT COUNT(note_id) 
FROM meeting_notes
WHERE meeting_id = 0;

SELECT file_path, file_type
FROM meeting_files
WHERE upload_date = '2023-03-26';

SELECT note_text
FROM meeting_notes
WHERE note_type = 'action item';

SELECT meeting_id, COUNT(*) AS note_count
FROM meeting_notes
GROUP BY meeting_id;

SELECT COUNT(file_id) AS total_minutes_files
FROM meeting_files
WHERE file_type = 'minutes';

SELECT COUNT(DISTINCT meeting_id) AS total_meetings_with_large_files
FROM meeting_files
WHERE file_size > 1;

SELECT COUNT(DISTINCT ma.meeting_id) AS total_unique_meetings_accessed
FROM meeting_access ma
WHERE ma.access_type IN ('view', 'download');
